import React from "react";

export default function Header({
  query,
  setQuery,
  category,
  setCategory,
  filters,
  setFilters,
  filteredCount,
  isMobile,
  searchOpen,
  setSearchOpen,
  openPanel,
  setOpenPanel,
  onLogoClick,
  onContactClick,
  setRandomMode,
}) {
  return (
    <div
      style={{
        background: "#ffffff",
        padding: "14px 24px",
        display: "flex",
        justifyContent: "space-between",
        alignItems: "center",
        position: "relative",
        zIndex: 100,
        borderBottom: "1px solid #e5e5e5",
      }}
    >
      {/* LOGO */}
      <img
        src="/logo.png"
        alt="Marist-Art"
        style={{
          height: "48px",
          cursor: "pointer",
          opacity: 0.9,
          transition: "opacity 0.2s ease",
        }}
        onMouseEnter={(e) => (e.currentTarget.style.opacity = 1)}
        onMouseLeave={(e) => (e.currentTarget.style.opacity = 0.9)}
        onClick={onLogoClick}
      />

      {/* CENTRO: menú escritorio o hamburguesa */}
      <div
        style={{
          display: "flex",
          alignItems: "center",
          gap: "20px",
          flex: 1,
          justifyContent: "center",
        }}
      >
        {!isMobile ? (
          <>
            {[
  { key: "todas", label: "Todas" },
  { key: "ilustracion", label: "Ilustraciones" },
  { key: "diseno", label: "Diseños" },
].map((cat) => {
  const active = category === cat.key;
  return (
    <span
      key={cat.key}
      onClick={() => {
        setQuery("");
        setFilters([]);
        setCategory(cat.key);
                    // Si pulsa "Todas", desactivar random
                    if (cat.key === "todas") setRandomMode(false);
                  }}
                  style={{
                    cursor: "pointer",
                    fontStyle: "italic",
                    color: active ? "#1a1a1a" : "#999999",
                    fontWeight: active ? "600" : "400",
                    fontSize: "13px",
                    transition: "color 0.2s ease",
                  }}
                >
                  {cat.label}
                </span>
              );
            })}

            <span
              onClick={onContactClick}
              style={{
                cursor: "pointer",
                fontStyle: "italic",
                color: "#999999",
                fontWeight: "400",
                fontSize: "13px",
                transition: "color 0.2s ease",
              }}
            >
              Contacto
            </span>
          </>
        ) : (
          <>
            <button
              onClick={() =>
                setOpenPanel(openPanel === "menu" ? null : "menu")
              }
              style={{
                border: "none",
                background: "transparent",
                fontSize: "22px",
                cursor: "pointer",
                color: "#1a1a1a",
              }}
            >
              ☰
            </button>

            {/* DESPLEGABLE MÓVIL */}
            {openPanel === "menu" && (
              <div
                style={{
                  position: "absolute",
                  top: "100%",
                  left: 0,
                  right: 0,
                  background: "#ffffff",
                  borderBottom: "1px solid #e5e5e5",
                  padding: "16px 24px",
                  display: "flex",
                  flexDirection: "column",
                  gap: "12px",
                  zIndex: 99,
                  boxShadow: "0 8px 20px rgba(0,0,0,0.1)",
                }}
              >
                {[
                  { key: "todas", label: "Todas" },
                  { key: "ilustracion", label: "Ilustraciones" },
                  { key: "diseno", label: "Diseños" },
                ].map((cat) => {
                  const active = category === cat.key;
                  return (
                    <span
                      key={cat.key}
                      onClick={() => {
                        setQuery("");
                        setFilters([]);
                        setCategory(cat.key);
                        setOpenPanel(null);
                      }}
                      style={{
                        cursor: "pointer",
                        color: active ? "#1a1a1a" : "#5c5c5c",
                        fontWeight: active ? "600" : "400",
                        fontSize: "16px",
                        fontStyle: "italic",
                        padding: "8px 0",
                        borderBottom: "1px solid #f5f5f5",
                      }}
                    >
                      {cat.label}
                    </span>
                  );
                })}

                <span
                  onClick={() => {
                    onContactClick();
                    setOpenPanel(null);
                  }}
                  style={{
                    cursor: "pointer",
                    color: "#5c5c5c",
                    fontSize: "16px",
                    fontStyle: "italic",
                    padding: "8px 0",
                  }}
                >
                  Contacto
                </span>
              </div>
            )}
          </>
        )}
      </div>

      {/* DERECHA: buscador */}
      <div style={{ display: "flex", alignItems: "center", gap: "12px" }}>
        {/* BUSCADOR CON EXPANSIÓN */}
        <div
          style={{
            display: "flex",
            alignItems: "center",
            gap: "8px",
            border: "1px solid #e5e5e5",
            borderRadius: "999px",
            padding: "6px 12px",
            background: "#ffffff",
            width: searchOpen ? "200px" : "36px",
            transition: "width 0.25s ease",
            overflow: "hidden",
          }}
        >
          <span
            onClick={() => setSearchOpen(!searchOpen)}
            style={{
              color: "#999999",
              cursor: "pointer",
              flexShrink: 0,
              fontSize: "14px",
            }}
          >
            🔍
          </span>

          <input
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            onFocus={() => setSearchOpen(true)}
            placeholder=""
            aria-label="Buscar ilustraciones"
            style={{
              border: "none",
              outline: "none",
              fontSize: "13px",
              width: "100%",
              background: "transparent",
              color: "#1a1a1a",
              fontFamily: "'Montserrat', sans-serif",
            }}
          />

          {query && (
            <span
              onClick={(e) => {
                e.preventDefault();
                setQuery("");
              }}
              onMouseDown={(e) => e.preventDefault()}
              role="button"
              aria-label="Borrar búsqueda"
              style={{
                cursor: "pointer",
                color: "#999999",
                fontSize: "13px",
                padding: "0 4px",
                userSelect: "none",
                flexShrink: 0,
              }}
            >
              ✕
            </span>
          )}
        </div>
      </div>
    </div>
  );
}
